function generate(input, lib) {
  const raw = (input && input.text != null) ? String(input.text)
             : (typeof input === 'string') ? input
             : '';
  const s = raw.toLowerCase();
  // Ordered rules. First-match wins. Order rationale:
  //   complaint first  -- strong-emotion words override the underlying topic
  //                       ("unacceptable, want to speak to a manager" is a
  //                       complaint, not an escalation request).
  //   escalate next    -- meta intent that overrides the underlying topic
  //                       ("escalation required, refund denied" is an escalate,
  //                       not a refund).
  //   password before account_lock -- 2FA / forgot-password should win over
  //                       a literal "locked out" reading.
  //   then refund, cancel, shipping, billing, feedback, other.
  if (/\b(awful|terrible|worst|rude|unhelpful|dissatisfied|unacceptable|complaint|complain|ignor(e|ing)|demand|waiting for \d+ days|no response|ongoing issue)\b/.test(s)) return { intent: 'complaint' };
  if (/\b(escalat\w*|supervisor|manage(r|ment)?|tier ?2|senior)\b/.test(s)) return { intent: 'escalate' };
  if (/\b(password|reset password|forgot.*password|2fa|two[- ]factor)\b/.test(s)) return { intent: 'password_reset' };
  if (/\b(locked|lockout|locked out|security lock|account.*(disabled|suspended|on hold|flagged)|unlock my account|cannot access account|restore.*account|account.*access)\b/.test(s)) return { intent: 'account_lock' };
  if (/\b(refund|money back|chargeback)\b/.test(s))          return { intent: 'refund' };
  if (/\bcancel(led|ling|lation)?\b|stop (my )?(plan|subscription|billing)|turn off (my )?subscription/.test(s)) return { intent: 'cancel' };
  if (/\b(track(ing)?|shipment|shipping|delivery|deliver(ed|y)?|package|expedite|reroute|where is my order|when will (my )?order|reroute order)\b/.test(s)) return { intent: 'shipping' };
  if (/\b(invoice|charge|charged|payment method|credit card|receipt|bill(ing|ed)?)\b/.test(s))   return { intent: 'billing' };
  if (/\b(thank|thanks|great|love|appreciate|feedback|suggestion|feature request|recommend)\b/.test(s)) return { intent: 'feedback' };
  return { intent: 'other' };
}
